import{_ as i,o as l,c as a,e}from"./app-4cb4de65.js";const h={},r=e('<h1 id="坚持-一种可以养成的习惯" tabindex="-1"><a class="header-anchor" href="#坚持-一种可以养成的习惯" aria-hidden="true">#</a> 坚持，一种可以养成的习惯</h1><h2 id="为什么你不能坚持" tabindex="-1"><a class="header-anchor" href="#为什么你不能坚持" aria-hidden="true">#</a> 为什么你不能坚持</h2><p>习惯是不依赖意志或毅力，对于外来的刺激做出无意识的或是条件反射式的反应，不用思考或努力就可以轻松做出反应。 习惯就是把重复的行动化为无意识的行动（自动化）​。 养成新习惯的过程就是打破平衡重建平衡。 习惯引力：抵抗新变化，维持现状。 以“农民”的眼光，撒下习惯的种子。</p><h3 id="七十项习惯清单建立-年度计划" tabindex="-1"><a class="header-anchor" href="#七十项习惯清单建立-年度计划" aria-hidden="true">#</a> 七十项习惯清单建立“年度计划”</h3><h4 id="自我投资" tabindex="-1"><a class="header-anchor" href="#自我投资" aria-hidden="true">#</a> 自我投资</h4><ul><li>阅读</li><li>影音学习</li><li>写日记</li><li>认识新朋友</li><li>学习专业知识</li><li>考资格证</li><li>参加研讨会、读书会</li><li>把在路上的时间转变为学习时间</li><li>利用博客、电子报发布信息</li><li>订阅刊物</li><li>重新检视人生计划</li><li>把一年的目标写在纸上</li></ul><h4 id="金钱" tabindex="-1"><a class="header-anchor" href="#金钱" aria-hidden="true">#</a> 金钱</h4><ul><li>存钱</li><li>节约</li><li>投资</li><li>填写家庭收支簿</li><li>不赌博</li><li>请他人吃饭</li><li>捐款</li></ul><h4 id="心灵成长-压力、动力" tabindex="-1"><a class="header-anchor" href="#心灵成长-压力、动力" aria-hidden="true">#</a> 心灵成长（压力、动力）</h4><ul><li>每天要说积极向上的话</li><li>每天写一件感恩的事</li><li>泡澡</li><li>每天都有一件期待的事</li><li>每周做一件有趣的事</li><li>整理</li><li>一天做三次深呼吸</li><li>听喜欢的音乐</li><li>问有建设性的问题</li><li>一天少做一件事（工作清单或备忘录）</li></ul><h4 id="运用时间" tabindex="-1"><a class="header-anchor" href="#运用时间" aria-hidden="true">#</a> 运用时间</h4><ul><li>不看电视</li><li>拟定第二天的计划</li><li>限定看电子邮件的次数</li><li>拒绝聚餐的邀请</li><li>杂事统一处理</li><li>先处理最重要的三件事</li><li>列工作清单</li><li>严守下班时间</li><li>提早进公司</li><li>一次只集中在一件事上</li><li>不断改善对时间的运用</li></ul><h4 id="人际关系" tabindex="-1"><a class="header-anchor" href="#人际关系" aria-hidden="true">#</a> 人际关系</h4><ul><li>经常称呼对方的名字</li><li>每天都要称赞他人</li><li>一天有 40%时间保持笑容</li><li>大声地与人打招呼</li><li>成为倾听的人</li><li>原谅他人</li><li>写交换日记</li><li>每天与重要的人交谈 10 分钟以上</li><li>不说抱怨、不满的话</li><li>先说结论</li><li>以双赢的目标思考</li></ul><h4 id="健康、美" tabindex="-1"><a class="header-anchor" href="#健康、美" aria-hidden="true">#</a> 健康、美</h4><ul><li>吃健康食品</li><li>把白米换成糙米</li><li>每天刷 3 次牙</li><li>吃天然食物</li><li>每天睡满 7 个小时</li><li>一天和 2 升水</li><li>每天晒太阳 30 分钟</li><li>不喝酒</li><li>讲究穿着</li><li>均衡摄取营养</li><li>饮食以蔬果为主</li><li>戒烟</li><li>肌力训练</li><li>做有氧运动</li><li>限制热量摄取</li><li>按摩</li><li>做伸展运动</li></ul><h2 id="顺理培养习惯的三个阶段" tabindex="-1"><a class="header-anchor" href="#顺理培养习惯的三个阶段" aria-hidden="true">#</a> 顺理培养习惯的三个阶段</h2><h3 id="反抗期【1-7】-很想放弃" tabindex="-1"><a class="header-anchor" href="#反抗期【1-7】-很想放弃" aria-hidden="true">#</a> 反抗期【1-7】：很想放弃</h3><ul><li>锁定一项习惯（不要同时培养多项习惯）</li><li>坚持有效的行动（行动规则越简单越好）</li><li>不要太在意结果</li><li>做麻烦的事=走向失败</li><li>配合目的，把记录内容减到最少</li></ul><h3 id="不稳定期【8-21】-容易被影响" tabindex="-1"><a class="header-anchor" href="#不稳定期【8-21】-容易被影响" aria-hidden="true">#</a> 不稳定期【8-21】：容易被影响</h3><h4 id="建立能够持续的机制" tabindex="-1"><a class="header-anchor" href="#建立能够持续的机制" aria-hidden="true">#</a> 建立能够持续的机制</h4><p>采取有弹性的计划以度过不稳定期</p><h4 id="行为模式化" tabindex="-1"><a class="header-anchor" href="#行为模式化" aria-hidden="true">#</a> 行为模式化</h4><h4 id="设定例外规则" tabindex="-1"><a class="header-anchor" href="#设定例外规则" aria-hidden="true">#</a> 设定例外规则</h4><h3 id="倦怠期【22-30】-感到厌烦" tabindex="-1"><a class="header-anchor" href="#倦怠期【22-30】-感到厌烦" aria-hidden="true">#</a> 倦怠期【22-30】：感到厌烦</h3><ul><li>设定小小的仪式</li><li>下决心惩罚自己</li><li>塑造有限的环境 营造有限的环境，建立不得不做的状况也是一种方法。例如，如果想减少加班，就在晚上八点安排一个约会；如果想整理，就在周日安排家庭聚会；如果想节约，钱包里就只放够一天花的钱。</li></ul>',26),d=[r];function n(t,c){return l(),a("div",null,d)}const u=i(h,[["render",n],["__file","坚持.html.vue"]]);export{u as default};
